import{o as i,c as n,j as a,e as r,n as s,ae as l,p as d}from"./chunks/framework.BSk3HXt1.js";const h={class:"bilingual-title"},c={key:0,class:"zh-text"},p={key:1,class:"en-text"},u={class:"language-toggle-wrapper"},g={class:"language-toggle-bar"},N=JSON.parse('{"title":"荷蘭重拳封禁劣跡色情網站 Motherless | Dutch Authorities Take Down Motherless Porn Site","description":"在 CNN 重磅深度調查報導所引發的龐大國際輿論壓力之下，長期託管未經同意傳播的私密影像與藥物性侵影片的惡劣色情網站 Motherless，已被荷蘭當局勒令下線並展開全面司法調查。","frontmatter":{"title":"荷蘭重拳封禁劣跡色情網站 Motherless | Dutch Authorities Take Down Motherless Porn Site","description":"在 CNN 重磅深度調查報導所引發的龐大國際輿論壓力之下，長期託管未經同意傳播的私密影像與藥物性侵影片的惡劣色情網站 Motherless，已被荷蘭當局勒令下線並展開全面司法調查。"},"headers":[],"relativePath":"news/porn-site-motherless-taken-down-dutch-authorities.md","filePath":"news/porn-site-motherless-taken-down-dutch-authorities.md"}'),v={name:"news/porn-site-motherless-taken-down-dutch-authorities.md"},w=Object.assign(v,{setup(b){const t=d("bilingual");return(m,e)=>(i(),n("div",null,[a("h1",h,[t.value!=="en"?(i(),n("span",c,"CNN 調查引爆國際怒火：荷蘭重拳突襲，勒令惡劣色情網站 Motherless 永久封鎖下線")):r("",!0),t.value!=="zh"?(i(),n("span",p,"Porn Website at Center of CNN Investigation Into Sexual Abuse Taken Offline by Dutch Authorities")):r("",!0)]),e[4]||(e[4]=a("div",{style:{"text-align":"center",margin:"24px 0 32px 0"}},[a("img",{src:"https://media.cnn.com/api/v1/images/stellar/prod/screenshot-2026-05-08-at-14-29-03-copy.jpg?c=16x9&q=w_800,c_fill",alt:"Motherless logo displayed on CNN",style:{"border-radius":"16px","max-width":"100%","box-shadow":"0 8px 32px rgba(0,0,0,0.15)",border:"1px solid rgba(255,255,255,0.08)"}})],-1)),a("div",u,[a("div",g,[a("button",{class:s(["language-toggle-btn",{active:t.value==="bilingual"}]),onClick:e[0]||(e[0]=o=>t.value="bilingual")},"中英雙語",2),a("button",{class:s(["language-toggle-btn",{active:t.value==="zh"}]),onClick:e[1]||(e[1]=o=>t.value="zh")},"純中文",2),a("button",{class:s(["language-toggle-btn",{active:t.value==="en"}]),onClick:e[2]||(e[2]=o=>t.value="en")},"純英文",2)])]),a("div",{class:s(["bilingual-article","mode-"+t.value])},[...e[3]||(e[3]=[l('<div class="bilingual-paragraph"><p class="zh-text">曾因長期託管與性別暴力及藥物促成性侵相關內容而面臨國際強烈審查的惡劣色情網站「Motherless」，在 CNN 重磅調查報導所引發的巨大國際輿論壓力與官方嚴密詰問下，已遭荷蘭當局強制撤除、永久下線。</p><p class="en-text">The porn website Motherless, which has faced international scrutiny over hosting content linked to gender-based violence and drug-facilitated sexual assault, has been taken offline by Dutch authorities following mounting pressure in the wake of a CNN investigation.</p></div><div class="bilingual-paragraph"><p class="zh-text">荷蘭檢察機關發言人向 CNN 證實，該非法網站已被荷蘭官方依法下架封禁，目前位於西蘭-西布拉班特（Zeeland-West-Braband）地區的檢察官辦公室，已正式針對該案啟動全面的刑事初步司法調查。</p><p class="en-text">A spokesperson for the Dutch Public Prosecution Service told CNN that the site had been taken down by Dutch authorities and that prosecutors in Zeeland-West-Braband had opened a preliminary investigation.</p></div><div class="bilingual-paragraph"><p class="zh-text">據信，該網站已於週四晚間時分被徹底切斷連線。Motherless 此前的核心伺服器全部架設在荷蘭境內，並由一家總部位於荷蘭南部小鎮斯滕貝亨（Steenbergen）名為 NFOrce 的互聯網科技服務公司提供硬體託管。</p><p class="en-text">The website appears to have been taken offline on Thursday evening. Motherless’ servers are located in the Netherlands and are hosted by NFOrce Internet Services, a company based in Steenbergen, in the south of the country.</p></div><div class="bilingual-paragraph"><p class="zh-text">此次事件的導火線源於 CNN 所發表的一項涵蓋範圍極廣的線上生態圈調查報告。報告詳盡揭露了該網站及其關聯的 Telegram 封閉群組，如何公然散布、傳播未經當事人同意的私密偷拍影像與慘絕人寰的藥物性侵害影片。先前由德國與加拿大獨立記者所發起的跨國調查，也曾在該平台發現了數以千計的受害女性在完全喪失意識狀態下慘遭性侵與凌虐的犯罪鐵證。</p><p class="en-text">Public attention focused on Motherless after CNN published its findings into a wider online ecosystem that highlighted the role that the site – and associated Telegram groups – play in hosting videos of non-consensual image sharing and drug-facilitated sexual assault. Previous investigations carried out by journalists in Germany and Canada also found thousands of videos in which unconscious women appeared to be raped and sexually abused.</p></div><hr><h2 class="bilingual-header"><span class="zh-text">💻 伺服器託管黑幕與輿論風暴</span><span class="en-text">Server Hosting Scandals &amp; Public Backlash</span></h2><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">荷蘭成不法溫床？NOS 接力踢爆</h3><span class="dish-card-badge">內幕 1</span></div><div class="bilingual-paragraph"><p class="zh-text">根據荷蘭國家廣播公司（NOS）的獨家報導，Motherless 的伺服器至少從 2024 年起就一直在荷蘭的領土上大搖大擺地運作。NOS 在 CNN 的全球調查曝光後，迅速鎖定並大篇幅報導了荷蘭本地設施與該平台的隱密聯繫，成為壓垮當局不作為的最後一根稻草，極大地激發了荷蘭民眾要求司法機關即刻介入鐵腕掃蕩的民意聲浪。</p><p class="en-text">The website has been hosted on Dutch servers since at least 2024, according to Dutch broadcaster NOS, whose reporting on the Netherlands’ connection to the platform in the wake of CNN’s investigation amplified calls for Dutch authorities to act.</p></div><div class="bilingual-paragraph"><p class="zh-text">NOS 與旗下的知名時事分析節目《Nieuwsuur》在聯合報導中精準指出，當局在針對 Motherless 上週首頁所陳列的 2 萬部精選短影音進行大數據分析後震驚地發現：貼有「亂倫」標籤的違法內容，居然高居全站點閱量之冠。而上週平台被播放最多次的置頂影片，更充斥著「性侵」、「親姊妹」以及「清純女學生」等令人作嘔的極端搜索關鍵字標籤。</p><p class="en-text">NOS and current affairs program Nieuwsuur reported that an analysis of 20,000 videos that appeared on the Motherless homepage last week found those tagged “incest” by users were among the site’s most-viewed categories, while one of the platform’s most-watched videos in the past week had also been tagged with “rape,” “sister” and “school girl.”</p></div></div><div class="dish-card"><div class="dish-card-header"><h3 class="dish-card-title">「沉睡」標籤背後的集體獸行</h3><span class="dish-card-badge">內幕 2</span></div><div class="bilingual-paragraph"><p class="zh-text">CNN 在 2026 年 3 月下旬發表重磅調查時首次踢爆，Motherless 內部竟圈養了高達 2 萬多部打著「熟睡（Sleep）」名義上傳的用戶原創影片，網站公然利用諸如 #passedout（不省人事）和 #eyecheck（眼球測試，專指用手指強行掰開受害者眼皮以確認其被下藥後完全失去知覺的恐怖測試）等邪惡標籤進行分類索引。雖然該網站在被 CNN 正式點名後火速把標籤做撤除掩飾，但許多涉嫌以藥物迷暈後實施性虐待的核心影片，直至本週為止依然沒有從資料庫中移除。</p><p class="en-text">CNN reported that Motherless was home to more than 20,000 videos of so-called “sleep” content uploaded by users, categorized using descriptive tags such as #passedout and #eyecheck at the time of publishing in late March 2026. While those tags appeared to have been removed since CNN’s report, content appearing to show drug-facilitated sexual abuse was still present as of this week.</p></div><div class="bilingual-paragraph"><p class="zh-text">伺服器託管公司 NFOrce 在週四的對外通告中，急於撇清干係，稱其已第一時間啟動了最進階的合規性與業務濫用緊急排查，並下達「最後通牒」，勒令 Motherless 必須在 12 小時內做出限期整改與說明。NFOrce 隨後在聲明中重申，其公司本身「並不參與、管理、審核或是控制任何租賃客戶平台底下的內容及營運行為」。「我們只不過是純粹的基礎電訊服務提供商。所有的濫用限制處置，都必須嚴格建立在收到依循司法管道與標準行政程序通報的基礎之上，」該公司解釋道。</p><p class="en-text">In a Thursday statement, NFOrce said that it had launched an urgent compliance and abuse-handling review, giving Motherless 12 hours to respond. NFOrce told CNN that it “does not operate, manage, moderate, or control customer platforms or their content.” “Our role is limited to infrastructure services. Abuse handling is performed based on reports received through established legal and operational procedures,” it said.</p></div></div><hr><h2 class="bilingual-header"><span class="zh-text">🗣️ 終結性犯罪：受害者的吶喊與漫長的正義之路</span><span class="en-text">Ending Sex Crimes: The Survivor&#39;s Voice &amp; The Long Road to Justice</span></h2><div class="bilingual-paragraph"><p class="zh-text">此次 Motherless 的徹底崩潰倒閉，代表了國際社會近年來在聯手打擊未經合意散佈猥褻性影像這一新興網路犯罪道路上，所摘下的最具指標性的一場偉大勝仗。</p><p class="en-text">The takedown of Motherless marks a major development in efforts to combat the spread of non-consensual imagery online.</p></div><div class="bilingual-paragraph"><p class="zh-text">總部位於荷蘭、長期致力於守護網路清朗邊界的獨立民間安全監督團體「Offlimits」的主管羅伯特·霍文（Robbert Hoving）對 CNN 坦言：政府當局終於肯揮起司法的重錘，正視這種將迫害女性的性暴力行為「包裝為常態性癖」、甚至「打造為暴利流量變現商業模型」的腐敗網站，釋放出了一個再明確不過的強烈警告訊號。但他同時也毫不留情地規勸：全球各國的相關立法機關必須從根本上推動「主動出擊」的積極介入機制，而絕對不能每次都只是被動地坐等慘劇和傷害徹底在網上擴散開來後，才亡羊補牢地要求業者把非法影片下架了事。</p><p class="en-text">Robbert Hoving of Offlimits, an independent online safety group based in the Netherlands, told CNN it was “a very important signal” from authorities that “websites normalizing sexual violence against woman, and turning that into a business model, are taken down.” But he added that regulators need to “proactively act. Not wait until it has happened by just taking content down.”</p></div><div class="bilingual-paragraph"><p class="zh-text">曾勇敢挺身而出、親自向 CNN 調查小組吐露自己如何慘遭同床共枕 16 年枕邊人以親生兒子的安眠藥暗中投毒侵犯的英國受害者佐伊·沃茨（Zoe Watts），日前攜手另一位受害者阿曼達·斯坦霍普（Amanda Stanhope）共同在社群發起了極具震撼力的 **#EndEyeCheck（終結下藥眼球測試）** 倡議運動。她感觸極深地說：「一想到這類喪心病狂的網站竟然能夠堂而皇之地存活在世人眼前、日復一日地縱容廣大女性被如此有系統地殘酷凌辱摧殘，就直教人反胃欲嘔。但是，今天看見當無數受害者並肩站在一起，加上世界上還有一群心懷正義的媒體做出真正紮實、深刻的追蹤報導時，那股改天換地的巨大能量，實在是太不可思議、也太令人動容了。」</p><p class="en-text">Zoe Watts, a British survivor of intimate partner drug-facilitated sexual assault who spoke with CNN for their investigation, and who, along with fellow survivor Amanda Stanhope recently launched the #EndEyeCheck campaign, said: “To even contemplate that the site was out there to begin with, women systematically being abused, is absolutely disgusting. But to see what the power of our standing united and good reporting has done is absolutely incredible.”</p></div><div class="bilingual-paragraph"><p class="zh-text">然而，本次的查禁行動也再度血淋淋地攤開了倖存者在對抗數位性犯罪時的最大痛處：在目前的互聯網分散式架構下，一旦私密淫穢素材被上傳成功，要想將它們從網際網路的世界裡徹底抹除簡直難如登天。許多女性權益倡導和前沿科技社群已經憂心忡忡地發出嚴正預警：這類唯利是圖的犯罪平台可以輕而易舉地藉由跨國轉移物理伺服器，或變更其全球網域名稱註冊所在地的方式，重新在賽博空間裡「借殼上市、死灰復燃」。</p><p class="en-text">But the takedown also highlights the difficulties survivors face in trying to remove exploitative material once it is uploaded and redistributed online. Advocacy and tech groups warn that the platform could easily resurface by migrating servers or domain locations.</p></div><div class="bilingual-paragraph"><p class="zh-text">Motherless 在今年 3 月份單月就創下了駭人聽聞的 8200 萬全球獨立造訪人次，而這其中最忠實的主力客群完全落座在美國境內。該網站厚顏無恥地在簡介中將自己封為「不帶任何世俗道德枷鎖的自由檔案寄存港灣——在這裡，只要有法律的擦邊球能打，任何東西都可以被永久珍藏在互聯網上」。細查之下更會發現，該非法站點的全球網域名稱大費周章地註冊在捷克共和國，而幕後的總公司主體卻登記在遙遠的中美洲哥斯大黎加。這正精準地揭露了目前所有被控託管剝削虐待性極端內容的非法網站的慣用核心詭計：刻意利用錯綜複雜的「多重司法管轄權」地理盲區與法規真空，人為製造極度巨大的國際跨國執法壁壘，從而阻撓、架空各國政府對於極端非法內容的強力監管。「如果未來這個邪惡的平台再次換個馬甲重出江湖，後果將會不堪設想，」霍文沉痛地呼籲道：「所有的幕後黑手與負責人必須真正面臨牢獄之災與刑事審判，我們的社會絕對不能只滿足於單純將一個網頁給和諧關閉而已。」</p><p class="en-text">Motherless, which recorded nearly 82 million visitors in March and whose core audience is in the United States, describes itself as a “moral free file host where anything legal is hosted forever.” The site’s domain name is registered in the Czech Republic, and its parent company is registered in Costa Rica. This reflects a common pattern among platforms accused of hosting abusive material: Leveraging multiple jurisdictions to complicate the regulation of extreme content. “The people responsible should be held accountable, and it shouldn’t stop with just taking it down,” Hoving said.</p></div><div class="original-source-wrapper"><div class="source-label"><span class="zh-text">🌐 閱讀英文原文：</span><span class="en-text">🌐 Read Original Article:</span></div><a href="https://edition.cnn.com/2026/05/08/europe/porn-site-motherless-taken-down-dutch-authorities-intl" target="_blank" rel="noopener noreferrer" class="source-link-btn"> CNN World <span style="font-size:0.8rem;">↗</span></a></div>',16)])],2)]))}});export{N as __pageData,w as default};
